# Entity classes using types from types module
from types import IIdentifiable, IMeasurable, Status, Dimensions

@abstract
class Entity(IIdentifiable):
    _id: int
    _name: str
    _status: Status

    def __init__(self, id: int, name: str):
        self._id = id
        self._name = name
        self._status = Status.PENDING

    @virtual
    def get_display_name(self) -> str:
        return self._name

    @virtual
    def activate(self) -> None:
        self._status = Status.ACTIVE

    def get_id(self) -> int:
        return self._id

    def get_status(self) -> Status:
        return self._status

class Product(Entity, IMeasurable):
    _dimensions: Dimensions
    _price: float

    def __init__(self, id: int, name: str, dims: Dimensions, price: float):
        super().__init__(id, name)
        self._dimensions = dims
        self._price = price

    @override
    def get_display_name(self) -> str:
        return f"Product: {self._name}"

    def get_area(self) -> float:
        return self._dimensions.width * self._dimensions.height

    def get_price(self) -> float:
        return self._price

class Service(Entity):
    _hourly_rate: float

    def __init__(self, id: int, name: str, rate: float):
        super().__init__(id, name)
        self._hourly_rate = rate

    @override
    def get_display_name(self) -> str:
        return f"Service: {self._name}"

    def estimate_cost(self, hours: int) -> float:
        return self._hourly_rate * float(hours)

    def get_hourly_rate(self) -> float:
        return self._hourly_rate

