# Utility functions for entity processing
from types import Status
from entities import Entity, Product, Service

def format_status(status: Status) -> str:
    return status.name

def calculate_total_value(items: list[Entity]) -> float:
    total: float = 0.0
    for item in items:
        if isinstance(item, Product):
            p = item as Product
            total = total + p.get_price()
        elif isinstance(item, Service):
            s = item as Service
            total = total + s.get_hourly_rate()
    return total

def count_by_status(items: list[Entity], status: Status) -> int:
    count: int = 0
    for item in items:
        if item.get_status() == status:
            count = count + 1
    return count

def get_entity_summary(item: Entity) -> str:
    return f"{item.get_display_name()} (ID: {item.get_id()})"
